+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -13,14 +13,16 @@ namespace Microsoft.AspNetCore.Components.Forms;
 internal static class ExpressionMemberAccessor
 {
     private static readonly ConcurrentDictionary<MemberInfo, string> _displayNameCache = new();
+    private static bool _isHotReloadSubscribed = false;

     static ExpressionMemberAccessor()
     {
-        if (HotReloadManager.Default.MetadataUpdateSupported)
+        if (!_isHotReloadSubscribed && HotReloadManager.Default.MetadataUpdateSupported)
         {
             HotReloadManager.Default.OnDeltaApplied += ClearCache;
+            _isHotReloadSubscribed = true;
         }
     }

     private static MemberInfo GetMemberInfo<TValue>(Expression<Func<TValue>> accessor)
"
