    "line": 46,
    "severity": "high",
    "description": "Inefficient expression comparison using reference equality. The code checks For != _previousFieldAccessor using reference equality, which only prevents recalculation if the exact same Expression object is reused. However, when parent components render with inline lambdas like For="@(m => m.Property)", a new Expression object is created each render, causing the reference comparison to always return true. This results in unnecessary GetDisplayName() calls on every parent render, even when accessing the same property. Combined with the unbounded cache growth issue, this cascades performance degradation.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -18,7 +18,6 @@ public class DisplayName<TValue> : IComponent
 {

     private RenderHandle _renderHandle;
-    private Expression<Func<TValue>>? _previousFieldAccessor;
     private string? _displayName;

     /// <summary>
@@ -43,17 +42,11 @@ public class DisplayName<TValue> : IComponent
             throw new InvalidOperationException($"{GetType()} requires a value for the " +
                 $"{nameof(For)} parameter.");
         }

-        // Only recalculate if the expression changed
-        if (For != _previousFieldAccessor)
+        var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
+
+        if (newDisplayName != _displayName)
         {
-            var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
-
-            if (newDisplayName != _displayName)
-            {
-                _displayName = newDisplayName;
-                _renderHandle.Render(BuildRenderTree);
-            }
-
-            _previousFieldAccessor = For;
+            _displayName = newDisplayName;
+            _renderHandle.Render(BuildRenderTree);
         }

         return Task.CompletedTask;
"
  }
